section.json_schema:
{
  "contract_type": "vendor|customer|employment|dpa|general",
  "risk_level": "high|medium|low",
  "risk_score": 0-100,
  "confidence_score": 0.0-1.0,

  "metadata": {
    "analyzed_date": "YYYY-MM-DD",
    "document_pages": 0,
    "has_exhibits": true|false,
    "is_signed": true|false,
    "language": "English|Other"
  },

  "parties": {
    "party_a": {
      "name": "Full legal entity name",
      "role": "Buyer|Seller|Employer|Employee|Service Provider|Customer|etc.",
      "jurisdiction": "State/Country of incorporation"
    },
    "party_b": {
      "name": "Full legal entity name",
      "role": "Buyer|Seller|Employer|Employee|Service Provider|Customer|etc.",
      "jurisdiction": "State/Country of incorporation"
    }
  },

  "key_dates": {
    "effective_date": "YYYY-MM-DD or 'Not specified'",
    "termination_date": "YYYY-MM-DD or 'Not specified' or 'Perpetual'",
    "initial_term": "X months/years",
    "renewal_terms": "Auto-renewal|Manual renewal|Expires without renewal",
    "renewal_notice_period_days": 0,
    "termination_notice_period_days": 0
  },

  "financial_summary": {
    "total_contract_value": "$X,XXX,XXX or 'Not specified' or 'Variable'",
    "payment_terms": "Net 30|Net 60|Upfront|etc.",
    "payment_schedule": "Monthly|Quarterly|Upon milestones|etc.",
    "late_payment_penalty": "X% per month|Not specified",
    "price_escalation": "Description of any price increase mechanisms",
    "currency": "USD|EUR|etc."
  },

  "liability_and_risk": {
    "liability_cap": "$X,XXX,XXX|Unlimited|Not specified",
    "liability_cap_as_multiple": "Xx months of fees|N/A",
    "indemnification": "Mutual|One-sided (we indemnify)|One-sided (they indemnify)|None",
    "insurance_requirements": "Description of required insurance",
    "force_majeure": "Comprehensive|Limited|Not present"
  },

  "critical_issues": [
    {
      "id": "CRIT-001",
      "category": "Liability|Payment|Termination|Compliance|IP|Data|Other",
      "severity": "critical",
      "title": "Brief issue title (e.g., 'Unlimited Liability Exposure')",
      "description": "Detailed description of the issue and why it's problematic",
      "clause_reference": "Section X.Y (Page Z) or exact quote if no section numbers",
      "risk_impact": "Explanation of potential consequences if not addressed",
      "recommendation": "Specific action to take (e.g., 'Negotiate liability cap of 12 months fees')",
      "priority": "immediate|high|medium"
    }
  ],

  "warnings": [
    {
      "id": "WARN-001",
      "category": "...",
      "severity": "medium|low",
      "title": "...",
      "description": "...",
      "clause_reference": "...",
      "recommendation": "..."
    }
  ],

  "positive_findings": [
    {
      "category": "Liability|Payment|Termination|IP|Other",
      "title": "Brief description of favorable term",
      "description": "Why this is beneficial",
      "clause_reference": "Section X.Y"
    }
  ],

  "missing_clauses": [
    {
      "clause_type": "Force Majeure|Limitation of Liability|Confidentiality|Data Privacy|etc.",
      "importance": "critical|high|medium|low",
      "reason": "Why this clause should be included",
      "suggested_language": "Brief example of what should be added (2-3 sentences max)"
    }
  ],

  "key_obligations": {
    "our_obligations": [
      {
        "obligation": "Description of what we must do",
        "deadline": "When it must be done",
        "clause_reference": "Section X.Y"
      }
    ],
    "their_obligations": [
      {
        "obligation": "Description of what they must do",
        "deadline": "When it must be done",
        "clause_reference": "Section X.Y"
      }
    ]
  },

  "termination_and_exit": {
    "termination_for_convenience": "Yes (XX days notice)|No|Asymmetric",
    "termination_for_cause": "Yes|No|Mutual|One-sided",
    "cure_period_days": 0,
    "termination_fees": "$X,XXX or 'None' or 'X months fees'",
    "data_return_required": true|false,
    "transition_assistance": "Yes|No|Not specified"
  },

  "dispute_resolution": {
    "governing_law": "State/Country",
    "venue": "Specific court or arbitration location",
    "mechanism": "Litigation|Arbitration|Mediation then Arbitration|etc.",
    "prevailing_party_fees": true|false
  },

  "recommendations": [
    {
      "priority": "high|medium|low",
      "action": "approve|negotiate|reject|clarify|seek_legal_review",
      "description": "Specific recommendation with rationale",
      "rationale": "Why this action is important"
    }
  ],

  "overall_assessment": "2-4 sentence executive summary of contract risk and recommendation",

  "next_steps": "Specific next actions for legal/business team"
}
